INSERT INTO `review` (`id`, `user_id`, `movie_id`, `rating`, `title`, `content`, `spoiler`, `like_count`, `status`, `create_time`, `update_time`) VALUES
                                                                                                                                                      (1, 21, 8, 9, '值得二刷的经典', '梦境与现实的边界在哪里？陀螺最后有没有停？诺兰给了我们一个开放式的结局，每个人都能有自己的解读。', 0, 71, 1, '2024-11-23 00:00:00', '2024-12-16 00:00:00'),
                                                                                                                                                      (3, 17, 7, 9, '演员演技炸裂', '诺兰把硬科幻拍成了诗。五维空间的视觉呈现、时间膨胀的概念，都在"爱能穿越一切"的主题下变得动人。', 1, 214, 1, '2024-04-04 00:00:00', '2024-04-22 00:00:00'),
                                                                                                                                                      (5, 4, 12, 10, '关于希望的最好诠释', '音乐的力量可以改变命运。马修老师用合唱打开了孩子们封闭的心灵，也改变了自己的人生。', 0, 309, 1, '2023-02-14 00:00:00', '2023-03-09 00:00:00'),
                                                                                                                                                      (6, 15, 3, 9, '人性的光辉与黑暗', '阿甘的奔跑贯穿了整部电影，他跑过了童年欺凌、跑过了越战、跑过了失去珍妮的痛苦。有时候，傻子比聪明人更懂得生活的真谛。', 1, 150, 1, '2024-08-14 00:00:00', '2024-08-20 00:00:00'),
                                                                                                                                                      (7, 23, 10, 9, '每个镜头都是艺术', '印度电影总能把教育话题拍得如此深刻。"追求卓越，成功就会在不经意间追上你"，这句话值得铭记。', 0, 437, 1, '2023-04-14 00:00:00', '2023-04-26 00:00:00'),
                                                                                                                                                      (8, 9, 12, 9, '细节决定成败', '音乐的力量可以改变命运。马修老师用合唱打开了孩子们封闭的心灵，也改变了自己的人生。', 0, 107, 1, '2024-12-19 00:00:00', '2025-01-17 00:00:00'),
                                                                                                                                                      (9, 22, 8, 9, '演员演技炸裂', '梦境与现实的边界在哪里？陀螺最后有没有停？诺兰给了我们一个开放式的结局，每个人都能有自己的解读。', 0, 236, 1, '2023-10-04 00:00:00', '2023-11-02 00:00:00'),
                                                                                                                                                      (10, 21, 2, 8, '走出影院，泪流满面', '程蝶衣不疯魔不成活，张国荣演活了这个角色。那句"我本是女娇娥，又不是男儿郎"道尽了一生的悲剧。', 0, 420, 1, '2023-11-20 00:00:00', '2023-12-02 00:00:00'),
                                                                                                                                                      (12, 30, 5, 9, '值得二刷的经典', '宫崎骏的想象力让人叹为观止。千寻从一个娇气的小女孩成长为勇敢独立的少女，这个过程温暖又治愈。', 0, 381, 1, '2025-02-03 00:00:00', '2025-02-21 00:00:00'),
                                                                                                                                                      (13, 14, 8, 10, '无法超越的高度', '梦境与现实的边界在哪里？陀螺最后有没有停？诺兰给了我们一个开放式的结局，每个人都能有自己的解读。', 0, 260, 2, '2023-04-04 00:00:00', '2023-04-28 00:00:00'),
                                                                                                                                                      (15, 15, 1, 9, '演员演技炸裂', '第一次看是在大学，当时只觉得好看。十年后再看，才真正理解其中深意。安迪用十九年挖通隧道，告诉我们希望是最好的东西。', 0, 349, 1, '2025-02-26 00:00:00', '2025-03-18 00:00:00'),
                                                                                                                                                      (17, 6, 17, 9, '这才是电影该有的样子', '兔子朱迪和狐狸尼克的故事告诉我们：不要被偏见定义，也不要用偏见定义别人。', 1, 101, 1, '2024-01-18 00:00:00', '2024-02-11 00:00:00'),
                                                                                                                                                      (19, 12, 8, 8, '这才是真正的神作', '梦境与现实的边界在哪里？陀螺最后有没有停？诺兰给了我们一个开放式的结局，每个人都能有自己的解读。', 1, 484, 1, '2023-03-29 00:00:00', '2023-04-21 00:00:00'),
                                                                                                                                                      (20, 16, 5, 10, '为什么我给满分', '宫崎骏的想象力让人叹为观止。千寻从一个娇气的小女孩成长为勇敢独立的少女，这个过程温暖又治愈。', 0, 484, 1, '2023-09-29 00:00:00', '2023-10-15 00:00:00');